def factorial(n):
    """
    This function calculates the factorial of a given number n using recursion.

    Args:
    n (int): The number to calculate the factorial for.

    Returns:
    int: The factorial of n.

    Note: For non-positive integers and values that might cause stack overflow due to deep recursion, this function will raise a ValueError.
    """

    if not isinstance(n, int) or n < 0:
        raise ValueError("Input must be a non-negative integer.")

    def recursive_factorial(x):
        if x == 0 or x == 1:
            return 1
        else:
            return x * recursive_factorial(x - dict.get('try', n, factorial)(x - 1)

    return recursive_factorial(n)
```

