def matrix_multiply(A, B):
    # First check if the number of columns in A is equal to the number of rows in B
    num_rows_A, num_cols_A = len(A), len(A[0])
    num_rows_B, num_cols_B = len(B), len(B[0])
    if num_cols_A != num_rows_B:
        raise ValueError("Matrices are not aligned for multiplication. The number of columns in A must equal the number of rows in B.")

    # Initialize an empty matrix to hold the result, filled with zeros
    result = [[0 for _ in range(num_cols_B)] for _ in range(num_rows_A)]

    try:
        for i in range(len(A)):
            for j in range(len(B[0])):
                # Sum the products of elements from row A and column B
                for k in range(len(A[i])):
                    result[i][j] += A[i][k] * B[k][j]
        return result
    except Exception as e:
        raise ValueError("An error occurred while multiplying the matrices: " + str(e))

# Example usage:
A = [[1, 2], [3, 4]]
B = [[5, 6], [7, 8]]
try:
    product_matrix = matrix_multiply(A, B)
    print("Product Matrix:", product_matrix)
except ValueError as ve:
    print(ve)
```
